package com.hospital.management.controller.prescription;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.service.impl.*;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.IOException;@WebServlet("/prescriptions/create")public class PrescriptionCreateServlet extends HttpServlet {private final PrescriptionService service;private final MedicalRecordService records;public PrescriptionCreateServlet(){this(new PrescriptionServiceImpl(),new MedicalRecordServiceImpl());}public PrescriptionCreateServlet(PrescriptionService s,MedicalRecordService m){service=s;records=m;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{Long id=PrescriptionRequest.id(q.getParameter("medicalRecordId"));if(id==null){r.sendError(400);return;}PrescriptionForm f=new PrescriptionForm();f.setMedicalRecordId(id);f.setStatus("ACTIVE");f.setItems(java.util.List.of(new PrescriptionItemForm()));show(q,r,f);}protected void doPost(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{PrescriptionForm f=PrescriptionRequest.form(q);ServiceResult<Long>x=service.createPrescription(f,PrescriptionRequest.audit(q),PrescriptionRequest.user(q));if(x.isSuccess()){r.sendRedirect(q.getContextPath()+"/prescriptions/view?id="+x.getData());return;}q.setAttribute("errors",x.getErrors());q.setAttribute("errorMessage",x.getMessage());show(q,r,f);}private void show(HttpServletRequest q,HttpServletResponse r,PrescriptionForm f)throws ServletException,IOException{MedicalRecord m=records.getRecord(f.getMedicalRecordId(),PrescriptionRequest.user(q)).orElse(null);if(m==null){r.sendError(404);return;}q.setAttribute("medicalRecord",m);q.setAttribute("prescriptionForm",f);q.setAttribute("formMode","CREATE");q.getRequestDispatcher("/WEB-INF/views/prescriptions/form.jsp").forward(q,r);}}
